namespace sv_04b958b253db4b46b9d90537eb0f9f6a.Services;

public class AppointmentService
{
    private static readonly List<string> Doctors =
    [
        "Dr. Smith",
        "Dr. Johnson",
        "Dr. Williams",
        "Dr. Brown"
    ];

    private static readonly Dictionary<string, List<string>> SelfPayDoctors = new()
    {
        // Dr. Smith does NOT accept self-pay; the others do.
        ["Dr. Johnson"] = [],
        ["Dr. Williams"] = [],
        ["Dr. Brown"] = []
    };

    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(new List<string>(Doctors));
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateOnly date)
    {
        // Stub: return a fixed set of time slots regardless of doctor/date.
        var slots = new List<string>
        {
            "9:00 AM",
            "10:00 AM",
            "11:00 AM",
            "1:00 PM",
            "2:00 PM",
            "3:00 PM"
        };
        return Task.FromResult(slots);
    }

    /// <summary>
    /// Validates server-side business rules. Returns a dictionary of
    /// field-name → error-message for any rule violations, or an empty
    /// dictionary when everything is valid.
    /// </summary>
    public Task<Dictionary<string, string>> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var errors = new Dictionary<string, string>();

        // Outstanding balance check
        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors["Email"] = "Account has outstanding balance";
        }

        // Self-pay check
        if (insuranceProvider == "None" && !SelfPayDoctors.ContainsKey(doctor))
        {
            errors["Doctor"] = "Selected doctor does not accept self-pay patients";
        }

        // Race-condition: slot just taken
        if (timeSlot == "10:00 AM")
        {
            errors["TimeSlot"] = "This slot is no longer available";
        }

        return Task.FromResult(errors);
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_04b958b253db4b46b9d90537eb0f9f6a.Services
@inject AppointmentService AppointmentSvc

<PageTitle>Book Appointment</PageTitle>

<h3 class="mb-4">Book a Medical Appointment</h3>

<EditForm Model="Model" OnValidSubmit="HandleSubmit">
    <DataAnnotationsValidator />

    @* ───── STEP 1: Patient Information ───── *@
    <fieldset>
        <legend>Step 1 &ndash; Patient Information</legend>

        <div class="mb-3">
            <label class="form-label" for="patientName">Patient Name</label>
            <InputText id="patientName" class="form-control" @bind-Value="Model.PatientName" />
            <ValidationMessage For="() => Model.PatientName" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="email">Email</label>
            <InputText id="email" class="form-control" @bind-Value="Model.Email" />
            <ValidationMessage For="() => Model.Email" />
            @if (serverErrors.TryGetValue("Email", out var emailErr))
            {
                <div class="validation-message">@emailErr</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label" for="phone">Phone</label>
            <InputText id="phone" class="form-control" @bind-Value="Model.Phone" />
            <ValidationMessage For="() => Model.Phone" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="insurance">Insurance Provider</label>
            <InputSelect id="insurance" class="form-select" @bind-Value="Model.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => Model.InsuranceProvider" />
        </div>

        @if (!showStep2)
        {
            <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">
                Next &rarr;
            </button>
        }
    </fieldset>

    @* ───── STEP 2: Appointment Details ───── *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Step 2 &ndash; Appointment Details</legend>

            <div class="mb-3">
                <label class="form-label" for="doctor">Preferred Doctor</label>
                <InputSelect id="doctor" class="form-select" @bind-Value="Model.Doctor"
                    @bind-Value:after="OnDoctorOrDateChanged">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.Doctor" />
                @if (serverErrors.TryGetValue("Doctor", out var docErr))
                {
                    <div class="validation-message">@docErr</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label" for="date">Date</label>
                <InputDate id="date" class="form-control" @bind-Value="Model.AppointmentDate"
                    @bind-Value:after="OnDoctorOrDateChanged" />
                <ValidationMessage For="() => Model.AppointmentDate" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="timeSlot">Time Slot</label>
                <InputSelect id="timeSlot" class="form-select" @bind-Value="Model.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in timeSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.TimeSlot" />
                @if (serverErrors.TryGetValue("TimeSlot", out var slotErr))
                {
                    <div class="validation-message">@slotErr</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label" for="reason">Reason for Visit</label>
                <InputTextArea id="reason" class="form-control" rows="3" @bind-Value="Model.Reason" />
                <ValidationMessage For="() => Model.Reason" />
            </div>

            <div class="d-flex gap-2">
                <button type="button" class="btn btn-secondary" @onclick="BackToStep1">
                    &larr; Back
                </button>
                <button type="button" class="btn btn-outline-primary" @onclick="CheckAvailability"
                    disabled="@isChecking">
                    @(isChecking ? "Checking…" : "Check Availability")
                </button>
                <button type="submit" class="btn btn-success" disabled="@(!availabilityConfirmed)">
                    Book Appointment
                </button>
            </div>
        </fieldset>
    }
</EditForm>

@if (booked)
{
    <div class="alert alert-success mt-4" role="alert">
        Appointment booked successfully!
    </div>
}

@code {
    private AppointmentFormModel Model { get; set; } = new();
    private List<string> doctors = [];
    private List<string> timeSlots = [];
    private Dictionary<string, string> serverErrors = new();
    private bool showStep2;
    private bool isChecking;
    private bool availabilityConfirmed;
    private bool booked;
    private EditContext? editContext;

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(Model);
        doctors = await AppointmentSvc.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        editContext = new EditContext(Model);
        // Validate only step-1 fields
        var isValid = true;
        var messages = new ValidationMessageStore(editContext);

        if (string.IsNullOrWhiteSpace(Model.PatientName))
        {
            messages.Add(() => Model.PatientName, "Patient Name is required.");
            isValid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.Email))
        {
            messages.Add(() => Model.Email, "Email is required.");
            isValid = false;
        }
        else if (!System.Text.RegularExpressions.Regex.IsMatch(
                     Model.Email,
                     @"^[^@\s]+@[^@\s]+\.[^@\s]+$"))
        {
            messages.Add(() => Model.Email, "Email format is invalid.");
            isValid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.Phone))
        {
            messages.Add(() => Model.Phone, "Phone is required.");
            isValid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.InsuranceProvider))
        {
            messages.Add(() => Model.InsuranceProvider, "Insurance Provider is required.");
            isValid = false;
        }

        editContext.NotifyValidationStateChanged();

        if (isValid)
        {
            showStep2 = true;
            serverErrors.Clear();
            availabilityConfirmed = false;
            booked = false;
        }
    }

    private void BackToStep1()
    {
        showStep2 = false;
        serverErrors.Clear();
        availabilityConfirmed = false;
    }

    private async Task OnDoctorOrDateChanged()
    {
        availabilityConfirmed = false;
        serverErrors.Clear();

        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate.HasValue)
        {
            timeSlots = await AppointmentSvc.GetAvailableTimeSlotsAsync(
                Model.Doctor,
                DateOnly.FromDateTime(Model.AppointmentDate.Value));
            // Reset slot when the list refreshes
            if (!timeSlots.Contains(Model.TimeSlot ?? ""))
            {
                Model.TimeSlot = null;
            }
        }
    }

    private async Task CheckAvailability()
    {
        serverErrors.Clear();
        availabilityConfirmed = false;

        // Client-side step-2 validation first
        editContext = new EditContext(Model);
        var messages = new ValidationMessageStore(editContext);
        var isValid = ValidateStep2(messages);
        editContext.NotifyValidationStateChanged();
        if (!isValid) return;

        isChecking = true;
        try
        {
            var result = await AppointmentSvc.ValidatePatientAsync(
                Model.Email,
                Model.InsuranceProvider,
                Model.Doctor!,
                Model.TimeSlot!);

            if (result.Count > 0)
            {
                serverErrors = result;
            }
            else
            {
                availabilityConfirmed = true;
            }
        }
        finally
        {
            isChecking = false;
        }
    }

    private bool ValidateStep2(ValidationMessageStore messages)
    {
        var valid = true;

        if (string.IsNullOrWhiteSpace(Model.Doctor))
        {
            messages.Add(() => Model.Doctor!, "Doctor is required.");
            valid = false;
        }
        if (!Model.AppointmentDate.HasValue)
        {
            messages.Add(() => Model.AppointmentDate!, "Date is required.");
            valid = false;
        }
        else if (Model.AppointmentDate.Value.Date <= DateTime.Today)
        {
            messages.Add(() => Model.AppointmentDate!, "Date must be in the future.");
            valid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.TimeSlot))
        {
            messages.Add(() => Model.TimeSlot!, "Time Slot is required.");
            valid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.Reason))
        {
            messages.Add(() => Model.Reason!, "Reason for Visit is required.");
            valid = false;
        }
        else if (Model.Reason!.Length > 500)
        {
            messages.Add(() => Model.Reason!, "Reason must be 500 characters or fewer.");
            valid = false;
        }

        return valid;
    }

    private void HandleSubmit()
    {
        if (availabilityConfirmed)
        {
            booked = true;
        }
    }

    public class AppointmentFormModel
    {
        public string PatientName { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
        public string InsuranceProvider { get; set; } = "";
        public string? Doctor { get; set; }
        public DateTime? AppointmentDate { get; set; }
        public string? TimeSlot { get; set; }
        public string? Reason { get; set; }
    }
}

