                <InputSelect id="timeSlot" class="form-select" @bind-Value="Model.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in timeSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.TimeSlot" />
                @if (serverErrors.TryGetValue("TimeSlot", out var slotErr))
                {
                    <div class="validation-message">@slotErr</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label" for="reason">Reason for Visit</label>
                <InputTextArea id="reason" class="form-control" rows="3" @bind-Value="Model.Reason" />
                <ValidationMessage For="() => Model.Reason" />
            </div>

            <div class="d-flex gap-2">
                <button type="button" class="btn btn-secondary" @onclick="BackToStep1">
                    &larr; Back
                </button>
                <button type="button" class="btn btn-outline-primary" @onclick="CheckAvailability"
                    disabled="@isChecking">
                    @(isChecking ? "Checking…" : "Check Availability")
                </button>
                <button type="submit" class="btn btn-success" disabled="@(!availabilityConfirmed)">
                    Book Appointment
                </button>
            </div>
        </fieldset>
    }
</EditForm>

@if (booked)
{
    <div class="alert alert-success mt-4" role="alert">
        Appointment booked successfully!
    </div>
}

@code {
    private AppointmentFormModel Model { get; set; } = new();
    private List<string> doctors = [];
    private List<string> timeSlots = [];
    private Dictionary<string, string> serverErrors = new();
    private bool showStep2;
    private bool isChecking;
    private bool availabilityConfirmed;
    private bool booked;
    private EditContext? editContext;

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(Model);
        doctors = await AppointmentSvc.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        editContext = new EditContext(Model);
        // Validate only step-1 fields
        var isValid = true;
        var messages = new ValidationMessageStore(editContext);

        if (string.IsNullOrWhiteSpace(Model.PatientName))
        {
            messages.Add(() => Model.PatientName, "Patient Name is required.");
            isValid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.Email))
        {
            messages.Add(() => Model.Email, "Email is required.");
            isValid = false;
        }
        else if (!System.Text.RegularExpressions.Regex.IsMatch(
                     Model.Email,
                     @"^[^@\s]+@[^@\s]+\.[^@\s]+$"))
        {
            messages.Add(() => Model.Email, "Email format is invalid.");
            isValid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.Phone))
        {
            messages.Add(() => Model.Phone, "Phone is required.");
            isValid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.InsuranceProvider))
        {
            messages.Add(() => Model.InsuranceProvider, "Insurance Provider is required.");
            isValid = false;
        }

        editContext.NotifyValidationStateChanged();

        if (isValid)
        {
            showStep2 = true;
            serverErrors.Clear();
            availabilityConfirmed = false;
            booked = false;
        }
    }

    private void BackToStep1()
    {
        showStep2 = false;
        serverErrors.Clear();
        availabilityConfirmed = false;
    }

    private async Task OnDoctorOrDateChanged()
    {
        availabilityConfirmed = false;
        serverErrors.Clear();

        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate.HasValue)
        {
            timeSlots = await AppointmentSvc.GetAvailableTimeSlotsAsync(
                Model.Doctor,
                DateOnly.FromDateTime(Model.AppointmentDate.Value));
            // Reset slot when the list refreshes
            if (!timeSlots.Contains(Model.TimeSlot ?? ""))
            {
                Model.TimeSlot = null;
            }
        }
    }

    private async Task CheckAvailability()
    {
        serverErrors.Clear();
        availabilityConfirmed = false;

        // Client-side step-2 validation first
        editContext = new EditContext(Model);
        var messages = new ValidationMessageStore(editContext);
        var isValid = ValidateStep2(messages);
        editContext.NotifyValidationStateChanged();
        if (!isValid) return;

        isChecking = true;
        try
        {
            var result = await AppointmentSvc.ValidatePatientAsync(
                Model.Email,
                Model.InsuranceProvider,
                Model.Doctor!,
                Model.TimeSlot!);

            if (result.Count > 0)
            {
                serverErrors = result;
            }
            else
            {
                availabilityConfirmed = true;
            }
        }
        finally
        {
            isChecking = false;
        }
    }

    private bool ValidateStep2(ValidationMessageStore messages)
    {
        var valid = true;

        if (string.IsNullOrWhiteSpace(Model.Doctor))
        {
            messages.Add(() => Model.Doctor!, "Doctor is required.");
            valid = false;
        }
        if (!Model.AppointmentDate.HasValue)
        {
            messages.Add(() => Model.AppointmentDate!, "Date is required.");
            valid = false;
        }
        else if (Model.AppointmentDate.Value.Date <= DateTime.Today)
        {
            messages.Add(() => Model.AppointmentDate!, "Date must be in the future.");
            valid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.TimeSlot))
        {
            messages.Add(() => Model.TimeSlot!, "Time Slot is required.");
            valid = false;
        }
        if (string.IsNullOrWhiteSpace(Model.Reason))
        {
            messages.Add(() => Model.Reason!, "Reason for Visit is required.");
            valid = false;
        }
        else if (Model.Reason!.Length > 500)
        {
            messages.Add(() => Model.Reason!, "Reason must be 500 characters or fewer.");
            valid = false;
        }

        return valid;
    }

    private void HandleSubmit()
    {
        if (availabilityConfirmed)
        {
            booked = true;
        }
    }

    public class AppointmentFormModel
    {
        public string PatientName { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
        public string InsuranceProvider { get; set; } = "";
        public string? Doctor { get; set; }
        public DateTime? AppointmentDate { get; set; }
        public string? TimeSlot { get; set; }
        public string? Reason { get; set; }
    }
}

